\begin{example}{1}[2025][全国2卷][高三][高考][第1题]

样本数据2，8，14，16，20的平均数为\blankbox
\begin{choices}
\choice{$8$}
\choice{$9$}
\choice{$12$}
\choice{$18$}
\end{choices}


\begin{proof}
	\begin{answer}
		C
	\end{answer}
	\begin{solutions}
		平均数计算公式：$\bar{x}=\dfrac{2+8+14+16+20}{5}=12$，故选C。
	\end{solutions}
\end{proof}
\end{example}

\begin{example}{1}[2025][全国2卷][高三][高考][第2题]

若$z=1+\text{i}$，则$\dfrac{1}{z-1}=$\blankbox
\begin{choices}
\choice{$-\text{i}$}
\choice{$\text{i}$}
\choice{$-1$}
\choice{$1$}
\end{choices}


\kaodian{复数-复数代数形式的四则运算-复数的加减-复数加减法的代数运算}
\begin{proof}
	\begin{answer}
		A
	\end{answer}
	\begin{solutions}
		由$z=1+\text{i}$，得$z-1=\text{i}$，则$\dfrac{1}{z-1}=\dfrac{1}{\text{i}}=-\text{i}$，故选A。
	\end{solutions}
\end{proof}
\end{example}

\begin{example}{1}[2025][全国2卷][高三][高考][第3题]
设集合$A=\{-4,0,1,2,8\}$，$B=\{x\mid x^3=x\}$，则$A\cap B=$\blankbox
\begin{choices}
\choice{$\{0,1,2\}$}
\choice{$\{1,2,8\}$}
\choice{$\{2,8\}$}
\choice{$\{0,1\}$}
\end{choices}
\begin{proof}
	\begin{answer}
		D
	\end{answer}
	\begin{solutions}
		由$x^3=x$得$x(x^2-1)=0$，解得$x=-1,0,1$，即$B=\{-1,0,1\}$。
		又$A=\{-4,0,1,2,8\}$，故$A\cap B=\{0,1\}$，选D。
	\end{solutions}
\end{proof}
\end{example}

