questions.question:
已知函数$f(x)=\ln(1+x)-x+\dfrac{1}{2}x^2-kx^3$，其中$0<k<\dfrac{1}{3}$．
\begin{enumerate}
    \item 证明：$f(x)$在$(0,+\infty)$存在唯一极值点和唯一零点；
    \item 设$x_1,x_2$为$f(x)$在$(0,+\infty)$的极值点和零点．
    \begin{enumerate}
        \item 设函数$g(t)=f(x_1+t)-f(x_1-t)$，证明：$g(t)$在$(0,x_1)$单调递减；
        \item 比较$2x_1$与$x_2$的大小，并证明．
    \end{enumerate}
\end{enumerate}

